const{Filemaker}=require("./Filemaker.js");const filemaker=new Filemaker("https://lib.mardens.com/fmutil","admin","19MRCC77!","Mardens_returns","Reports-ListView");filemaker.getRecordCount().then(count=>filemaker.getRecords(1,0)).then(records=>{let completed=0;records.forEach(record=>{record=record["fields"];function formatToDesired(date){const year=date.getUTCFullYear();const month=`0${date.getUTCMonth()+1}`.slice(-2);const day=`0${date.getUTCDate()}`.slice(-2);const hours=`0${date.getUTCHours()}`.slice(-2);const minutes=`0${date.getUTCMinutes()}`.slice(-2);const seconds=`0${date.getUTCSeconds()}`.slice(-2);const milliseconds=`00${date.getUTCMilliseconds()}`.slice(-6);return`${year}-${month}-${day} ${hours}:${minutes}:${seconds}.${milliseconds}`}const date=new Date(record["CreatedDate"]);const formattedDate=formatToDesired(date);const item={id:-1,date:formattedDate,first_name:record["Customers::FirstName"],last_name:record["Customers::LastName"],email:"",phone:record["Customers::phone"],type:1,card:{id:-1,date:formattedDate,amount:record["Amount"],card:record["CardNumber"]},employee:record["IssuedBy"],store:{id:-1,city:record["store"],address:""},customerAddress:{id:-1,street:record["Customers::Address"],city:record["Customers::City"],state:record["Customers::State"],zip:record["Customers::Zip"]}};process.env.NODE_TLS_REJECT_UNAUTHORIZED="0";fetch("http://returns.local/api/",{method:"POST",body:JSON.stringify(item),headers:{"Content-Type":"application/json"}}).then(()=>{completed++;console.log(`Processed ${completed}/${records.length} (${completed/records.length}%) records.`)}).catch(console.error)})});